import logging
import json
import os
import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient, EventGridEvent
from datetime import datetime

app = func.FunctionApp()

# Environment variables
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT")
COSMOS_DATABASE = os.environ.get("COSMOS_DATABASE")
COSMOS_CONTAINER = os.environ.get("COSMOS_CONTAINER")
EVENT_GRID_ENDPOINT = os.environ.get("EVENT_GRID_ENDPOINT")

@app.blob_trigger(arg_name="myblob", path="input-container/{name}",
                  connection="STORAGE_ACCOUNT_CONNECTION")
def process_blob(myblob: func.InputStream):
    logging.info(f"Processing blob: {myblob.name}, Size: {myblob.length} bytes")
    
    # Use DefaultAzureCredential with Managed Identity
    credential = DefaultAzureCredential()
    
    try:
        # Read blob content
        blob_content = myblob.read().decode('utf-8')
        
        # Process the file
        processed_data = process_file_content(blob_content, myblob.name)
        
        # Write to Cosmos DB with least privilege scope
        write_to_cosmos(credential, processed_data)
        
        # Send notification via Event Grid
        send_notification(credential, myblob.name, processed_data)
        
        logging.info(f"Successfully processed blob: {myblob.name}")
        
    except Exception as e:
        logging.error(f"Error processing blob {myblob.name}: {str(e)}")
        raise

def process_file_content(content: str, filename: str) -> dict:
    """Process file content and return structured data"""
    try:
        data = json.loads(content)
    except json.JSONDecodeError:
        data = {"raw_content": content}
    
    return {
        "id": f"{filename}_{datetime.utcnow().timestamp()}",
        "filename": filename,
        "processed_at": datetime.utcnow().isoformat(),
        "data": data,
        "status": "processed"
    }

def write_to_cosmos(credential, data: dict):
    """Write processed data to Cosmos DB using scoped permissions"""
    # Use specific database and container scope instead of account-level permissions
    cosmos_client = CosmosClient(
        url=COSMOS_ENDPOINT,
        credential=credential
    )
    
    database = cosmos_client.get_database_client(COSMOS_DATABASE)
    container = database.get_container_client(COSMOS_CONTAINER)
    
    # Only write to specific container, not account-wide access
    container.upsert_item(data)
    logging.info(f"Data written to Cosmos DB: {data['id']}")

def send_notification(credential, filename: str, data: dict):
    """Send notification via Event Grid using scoped permissions"""
    # Use specific topic endpoint instead of broad Event Grid permissions
    event_grid_client = EventGridPublisherClient(
        endpoint=EVENT_GRID_ENDPOINT,
        credential=credential
    )
    
    event = EventGridEvent(
        event_type="BlobProcessing.Completed",
        data={
            "filename": filename,
            "processed_id": data["id"],
            "status": data["status"],
            "timestamp": data["processed_at"]
        },
        subject=f"blob/{filename}",
        data_version="1.0"
    )
    
    event_grid_client.send([event])
    logging.info(f"Notification sent for: {filename}")


# Additional HTTP trigger for manual processing with authentication
@app.route(route="process", auth_level=func.AuthLevel.FUNCTION)
def manual_process(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Manual process trigger received')
    
    try:
        blob_name = req.params.get('blob_name')
        if not blob_name:
            return func.HttpResponse(
                "Please provide blob_name parameter",
                status_code=400
            )
        
        credential = DefaultAzureCredential()
        
        # Use specific container scope for blob access
        blob_service_client = BlobServiceClient(
            account_url=STORAGE_ACCOUNT_URL,
            credential=credential
        )
        
        # Access specific container only
        container_client = blob_service_client.get_container_client("input-container")
        blob_client = container_client.get_blob_client(blob_name)
        
        # Download and process
        blob_data = blob_client.download_blob().readall().decode('utf-8')
        processed_data = process_file_content(blob_data, blob_name)
        
        write_to_cosmos(credential, processed_data)
        send_notification(credential, blob_name, processed_data)
        
        return func.HttpResponse(
            json.dumps({"status": "success", "processed_id": processed_data["id"]}),
            mimetype="application/json",
            status_code=200
        )
        
    except Exception as e:
        logging.error(f"Error in manual process: {str(e)}")
        return func.HttpResponse(
            json.dumps({"status": "error", "message": str(e)}),
            mimetype="application/json",
            status_code=500
        )